import{_ as o,o as t,c as n,ag as i}from"./chunks/framework.cqfd-qMR.js";const h=JSON.parse('{"title":"Changelog","description":"","frontmatter":{},"headers":[],"relativePath":"changelog.md","filePath":"changelog.md"}'),r={name:"changelog.md"};function a(c,e,d,s,l,g){return t(),n("div",null,[...e[0]||(e[0]=[i('<h1 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h1><p>All notable changes to the Glance project will be documented in this file.</p><h2 id="v0-2-5-2026-03-06" tabindex="-1">[v0.2.5] - 2026-03-06 <a class="header-anchor" href="#v0-2-5-2026-03-06" aria-label="Permalink to &quot;[v0.2.5] - 2026-03-06&quot;">​</a></h2><ul><li><strong>Clipboard Fallback</strong>: Implemented a fallback mechanism for the Clipboard API using <code>document.execCommand(&#39;copy&#39;)</code> to support non-secure contexts (HTTP).</li><li><strong>HTTP Support</strong>: Fixed <code>Uncaught TypeError: Cannot read properties of undefined (reading &#39;writeText&#39;)</code> when accessing the dashboard over a remote IP via HTTP.</li><li><strong>Improved UI Reliability</strong>: Updated all copy buttons (Integrations, Traffic Details, and MCP Docs) to use the new robust clipboard utility.</li></ul><h2 id="v0-2-4-2026-03-05" tabindex="-1">[v0.2.4] - 2026-03-05 <a class="header-anchor" href="#v0-2-4-2026-03-05" aria-label="Permalink to &quot;[v0.2.4] - 2026-03-05&quot;">​</a></h2><ul><li><strong>MCP One-Click Interception</strong>: Enhanced MCP server with specialized tools for one-click interception of Docker containers, Android devices, and Java processes.</li><li><strong>Improved Tooling</strong>: Added <code>intercept_docker_container</code>, <code>intercept_android_device</code>, and <code>intercept_java_process</code> to the Model Context Protocol (MCP) toolset.</li><li><strong>Reliable Automation</strong>: Integrated robust container recreation logic and environment injection directly into the AI agent workflow.</li></ul><h2 id="v0-2-3-2026-03-05" tabindex="-1">[v0.2.3] - 2026-03-05 <a class="header-anchor" href="#v0-2-3-2026-03-05" aria-label="Permalink to &quot;[v0.2.3] - 2026-03-05&quot;">​</a></h2><ul><li><strong>Terminal Interception</strong>: Redesigned setup script with improved compatibility and feedback.</li><li><strong>Local Interception</strong>: Default behavior now unsets <code>NO_PROXY</code> to intercept <code>localhost</code> traffic by default.</li><li><strong>Enhanced Tool Support</strong>: Added CA certificate environment variables for <code>curl</code>, <code>git</code>, <code>pip</code>, and <code>npm</code> (<code>CURL_CA_BUNDLE</code>, <code>GIT_SSL_CAINFO</code>, etc.).</li><li><strong>Port Standardization</strong>: Standardized default ports across documentation and code: <code>15501</code> for Dashboard/API and <code>15500</code> for Proxy.</li><li><strong>Improved Feedback</strong>: The terminal setup script now provides real-time feedback and success logs during configuration.</li><li><strong>Testing</strong>: Added <code>InitTestDB</code> for reliable in-memory database testing and added an integration test for terminal interception.</li></ul><h2 id="v0-2-2-2026-02-24" tabindex="-1">[v0.2.2] - 2026-02-24 <a class="header-anchor" href="#v0-2-2-2026-02-24" aria-label="Permalink to &quot;[v0.2.2] - 2026-02-24&quot;">​</a></h2><ul><li><strong>Mock Rules Engine</strong>: New interactive mock editor with JSON tree view and switchable mocking rules.</li><li><strong>Docker Networking</strong>: Enhanced host resolution using <code>host.docker.internal</code> for Docker Desktop environments.</li><li><strong>Docker Auto-injection</strong>: Automatic <code>ExtraHosts</code> injection during container recreation for better connectivity.</li><li><strong>Documentation</strong>: Migrated to VitePress with new branding, dark/light themes, and detailed installation guidelines.</li><li><strong>Visuals</strong>: Added dashboard screenshots, favicons, and social assets to documentation.</li><li><strong>Project Hygiene</strong>: Integrated GitHub Sponsors and refined multi-platform release pipeline.</li></ul><h2 id="v0-2-1-2026-02-23" tabindex="-1">[v0.2.1] - 2026-02-23 <a class="header-anchor" href="#v0-2-1-2026-02-23" aria-label="Permalink to &quot;[v0.2.1] - 2026-02-23&quot;">​</a></h2><ul><li><strong>Improved Host Resolution</strong>: Enhanced Host IP discovery to prioritize <code>host.docker.internal</code> for Docker Desktop users.</li><li><strong>ExtraHosts Injection</strong>: Automatically included <code>host.docker.internal:host-gateway</code> in <code>ExtraHosts</code> during container recreation to ensure reliable host resolution across all platforms (Linux/macOS/Windows).</li></ul><h2 id="v0-2-0-2026-02-23" tabindex="-1">[v0.2.0] - 2026-02-23 <a class="header-anchor" href="#v0-2-0-2026-02-23" aria-label="Permalink to &quot;[v0.2.0] - 2026-02-23&quot;">​</a></h2><ul><li><strong>Docker Interception</strong>: Introduced a robust &quot;One-Click Intercept&quot; for Docker containers via container recreation and environment injection.</li><li><strong>Java Container Support</strong>: Added specialized logic to automatically inject and trust the Glance CA certificate into the Java Trust Store (<code>cacerts</code>) inside Docker containers using <code>keytool</code>.</li><li><strong>Universal Compatibility</strong>: Replaced the <code>iptables</code> approach with standard <code>HTTP_PROXY</code>/<code>HTTPS_PROXY</code> and <code>JAVA_TOOL_OPTIONS</code> injection, ensuring compatibility across all container OS flavors (Alpine, Debian, RHEL) without requiring <code>NET_ADMIN</code> capabilities.</li><li><strong>Docker UI</strong>: New full-width Docker Containers card in the Integrations view with real-time status tracking, container renaming for backups, and seamless restoration.</li><li><strong>API Stability</strong>: Fixed Docker SDK compatibility issues for older daemon versions (API 1.41) and properly handled binary stream demultiplexing for command execution.</li></ul>',14)])])}const p=o(r,[["render",a]]);export{h as __pageData,p as default};
